def mapIconBarIdToRepresentation(id){
      	if (id == 'usm_haller') {
      		return 'IconBar_Regal';
      	}
      	if (id == 'usm_hallertisch') {
      		return 'IconBar_Tisch';
      	}
      	if (id == 'usm_addons') {
      		return 'IconBar_Addons';
      	}
      	if (id == 'space_configurator') {
      		return 'iconbar_space';
      	}
		return id;
};

