def hasPartsOnPrintZone(usmzone) {
	my p1= Vector(0,0,-10);
	my p2= Vector(0,0,400);
	/*p1 and p2 define the intersection ray in the local coordinate system of the 
	 part*/
	my zonepos = PolyCentroid(usmzone['pointlist']); 
	my center= VectorAdd(zonepos, p1);
	my direction= VectorSub(VectorAdd(zonepos,p2), center);
	/* center and direction are now in the global coordinate system */
	my info= GetIntersectionInfo(1000, Line(center, direction),'', null);

	if (info['part'] ne null) {
	  return true;
	} else {
	  return false;
	};
};

def setCategory(id) {
			my state = false;
		  if (id eq 'blacklines') {
		  	state = IsSubTypeOf('rohr') or IsSubTypeOf('kugel') or 
				        IsSubTypeOf('tischbein') or IsSubTypeOf('tischzarge') or 
				        IsSubTypeOf('ct_saeule') or IsSubTypeOf('traegerrohr') or 
				        IsSubTypeOf('ct_saeule_e_tisch') or IsSubTypeOf('ct_saeule_m_tisch');
      } else if (id eq 'onlylines') {
						state = IsSubTypeOf('ct_tischblatt');
			} else if (id eq 'transparent') {  	
						state = (IsSubTypeOf('haller_shelf_component') or 
		                 IsSubTypeOf('ct_primo') or 
		                 IsSubTypeOf('haller_table_component') or 
		                 IsSubTypeOf('ct_kitos_component') or 
		                 IsSubTypeOf('ct_kastenset')) 
		                 and not call setCategory('blacklines')
		                 and not IsSubTypeOf('tischblatt') 
		                 and not call setCategory('onlylines');
		      }
      return state;
    }
